// Define a middleware function to validate the 'username' parameter
var validateUsername = function(req, res, next) {
    // Get the username parameter from the URL path
    var username = req.params.username;

    // Check if the username is empty
    if (!username) {
        // Return a 400 error with a message
        res.status(400).send({ error: 'Missing username parameter' });
    } else {
        // Call the next middleware function in the chain
        next();
    }
};

